import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { ScrollArea } from '@/components/ui/scroll-area';
import { ShieldCheck, AlertTriangle, CheckCircle2, TrendingUp, Zap, Sparkles, BrainCircuit } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

interface AuditResult {
    compliance_score?: number;
    quality_score?: number;
    performance_score?: number;
    policy_compliance_score?: number;
    ai_analysis?: {
        quality_score?: number;
        features?: string[];
        strengths?: string[];
        weaknesses?: string[];
        suggestions?: string[];
        tone_analysis?: string;
        policy_warnings?: string[];
    };
    issues?: Array<{
        type: string;
        severity: string;
        message: string;
    }>;
}

interface AiDiagnosisModalProps {
    isOpen: boolean;
    onClose: () => void;
    data: AuditResult | null;
    isLoading: boolean;
    onReanalyze?: () => void;
    title?: string;
}

export function AiDiagnosisModal({ isOpen, onClose, data, isLoading, onReanalyze, title = "Diagnóstico IA" }: AiDiagnosisModalProps) {
    const score = data?.compliance_score || data?.ai_analysis?.quality_score || 0;
    const policyScore = data?.policy_compliance_score || 100;

    // Determine status color/text
    const getStatus = (s: number) => {
        if (s >= 80) return { color: 'text-emerald-500', bg: 'bg-emerald-500', label: 'EXCELENTE' };
        if (s >= 50) return { color: 'text-amber-500', bg: 'bg-amber-500', label: 'ATENÇÃO' };
        return { color: 'text-rose-500', bg: 'bg-rose-500', label: 'CRÍTICO' };
    };

    const status = getStatus(score);

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="max-w-2xl bg-[#0A0A0A] border-white/10 p-0 overflow-hidden shadow-2xl">
                <DialogHeader className="p-6 border-b border-white/5 bg-white/[0.02]">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-ch-orange/10 rounded-lg">
                            <Sparkles className="w-5 h-5 text-ch-orange" />
                        </div>
                        <div>
                            <DialogTitle className="text-xl font-bold uppercase tracking-tight text-white">{title}</DialogTitle>
                            <DialogDescription className="text-ch-text-dimmed uppercase text-xs tracking-widest font-bold mt-1">
                                Análise Neural de Performance e Compliance
                            </DialogDescription>
                        </div>
                    </div>
                </DialogHeader>

                <ScrollArea className="max-h-[70vh]">
                    <div className="p-8 space-y-8">
                        {isLoading ? (
                            <div className="flex flex-col items-center justify-center py-20 gap-6">
                                <div className="relative">
                                    <div className="w-20 h-20 border-4 border-white/5 rounded-full animate-[spin_3s_linear_infinite]" />
                                    <div className="w-20 h-20 border-4 border-t-ch-orange border-r-transparent border-b-transparent border-l-transparent rounded-full absolute top-0 left-0 animate-[spin_1s_ease-in-out_infinite]" />
                                    <BrainCircuit className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-8 h-8 text-white opacity-50 animate-pulse" />
                                </div>
                                <p className="text-sm font-bold text-ch-text-dimmed uppercase tracking-widest animate-pulse">Processando Diagnóstico...</p>
                            </div>
                        ) : data ? (
                            <motion.div
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="space-y-8"
                            >
                                {/* Scores */}
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="p-6 rounded-3xl bg-white/[0.02] border border-white/5 flex flex-col items-center justify-center text-center relative overflow-hidden group">
                                        <div className={`absolute inset-0 opacity-[0.03] ${status.bg}`} />
                                        <span className={`text-6xl font-black ${status.color} tabular-nums tracking-tighter mb-2`}>{score}</span>
                                        <span className={`text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full bg-white/5 ${status.color}`}>Score de Qualidade</span>
                                    </div>
                                    <div className="p-6 rounded-3xl bg-white/[0.02] border border-white/5 flex flex-col items-center justify-center text-center relative overflow-hidden">
                                        <div className={`absolute inset-0 opacity-[0.03] ${getStatus(policyScore).bg}`} />
                                        <span className={`text-6xl font-black ${getStatus(policyScore).color} tabular-nums tracking-tighter mb-2`}>{policyScore}%</span>
                                        <span className="text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full bg-white/5 text-ch-text-dimmed">Compliance Code</span>
                                    </div>
                                </div>

                                {/* AI Strengths */}
                                {data.ai_analysis?.strengths && data.ai_analysis.strengths.length > 0 && (
                                    <div className="space-y-4">
                                        <div className="flex items-center gap-2 text-emerald-500">
                                            <CheckCircle2 className="w-4 h-4" />
                                            <h4 className="text-xs font-black uppercase tracking-widest">Pontos Fortes Detectados</h4>
                                        </div>
                                        <div className="grid gap-2">
                                            {data.ai_analysis.strengths.map((item, i) => (
                                                <div key={i} className="p-3 rounded-lg bg-emerald-500/5 border border-emerald-500/10 text-emerald-200/80 text-sm font-medium">
                                                    {item}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                {/* AI Weaknesses */}
                                {data.ai_analysis?.weaknesses && data.ai_analysis.weaknesses.length > 0 && (
                                    <div className="space-y-4">
                                        <div className="flex items-center gap-2 text-amber-500">
                                            <AlertTriangle className="w-4 h-4" />
                                            <h4 className="text-xs font-black uppercase tracking-widest">Pontos de Atenção</h4>
                                        </div>
                                        <div className="grid gap-2">
                                            {data.ai_analysis.weaknesses.map((item, i) => (
                                                <div key={i} className="p-3 rounded-lg bg-amber-500/5 border border-amber-500/10 text-amber-200/80 text-sm font-medium">
                                                    {item}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                {/* Policy Warnings */}
                                {data.ai_analysis?.policy_warnings && data.ai_analysis.policy_warnings.length > 0 && (
                                    <div className="space-y-4">
                                        <div className="flex items-center gap-2 text-rose-500">
                                            <ShieldCheck className="w-4 h-4" />
                                            <h4 className="text-xs font-black uppercase tracking-widest">Alertas de Política (Risco de Bloqueio)</h4>
                                        </div>
                                        <div className="grid gap-2">
                                            {data.ai_analysis.policy_warnings.map((item, i) => (
                                                <div key={i} className="p-3 rounded-lg bg-rose-500/5 border border-rose-500/10 text-rose-200/80 text-sm font-medium">
                                                    {item}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                {/* Optimization Suggestions */}
                                {data.ai_analysis?.suggestions && data.ai_analysis.suggestions.length > 0 && (
                                    <div className="space-y-4">
                                        <div className="flex items-center gap-2 text-ch-orange">
                                            <Zap className="w-4 h-4" />
                                            <h4 className="text-xs font-black uppercase tracking-widest">Plano de Otimização Sugerido</h4>
                                        </div>
                                        <div className="grid gap-2">
                                            {data.ai_analysis.suggestions.map((item, i) => (
                                                <div key={i} className="p-4 rounded-xl bg-white/5 border border-white/5 text-ch-white text-sm leading-relaxed flex gap-3 group hover:border-ch-orange/30 transition-colors">
                                                    <span className="text-ch-orange font-black text-xs mt-0.5">{i + 1}.</span>
                                                    {item}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                            </motion.div>
                        ) : (
                            <div className="text-center py-10 text-ch-text-dimmed uppercase text-xs font-bold tracking-widest">
                                Nenhuma análise disponível. Execute o diagnóstico.
                            </div>
                        )}
                    </div>
                </ScrollArea>

                <div className="p-6 border-t border-white/5 bg-white/[0.02] flex justify-end gap-3 px-6">
                    <Button variant="outline" onClick={onClose} className="h-12 px-6 rounded-xl border-white/10 hover:bg-white/5 text-xs font-bold uppercase tracking-widest">
                        Fechar
                    </Button>
                    {onReanalyze && (
                        <Button
                            onClick={onReanalyze}
                            disabled={isLoading}
                            className="h-12 px-6 rounded-xl bg-ch-orange hover:bg-ch-orange/90 text-black text-xs font-black uppercase tracking-widest shadow-lg shadow-ch-orange/20"
                        >
                            {isLoading ? 'Processando...' : 'Rodar Novo Diagnóstico'}
                        </Button>
                    )}
                </div>
            </DialogContent>
        </Dialog>
    );
}

import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { AdSetStepData } from "@/types/campaign-wizard";
import { format } from "date-fns";

interface StepAdSetProps {
    data: AdSetStepData;
    updateData: (data: Partial<AdSetStepData>) => void;
}

export default function StepAdSet({ data, updateData }: StepAdSetProps) {

    const handleBudgetChange = (amount: string) => {
        // Convert float to cents integer
        const val = parseFloat(amount.replace(',', '.'));
        if (!isNaN(val)) {
            updateData({ daily_budget: Math.round(val * 100) });
        }
    };

    const currentBudget = data.daily_budget ? (data.daily_budget / 100).toFixed(2) : '0.00';

    return (
        <div className="space-y-6 animate-in slide-in-from-right-4">
            <div className="space-y-2">
                <h2 className="text-xl font-semibold text-ch-white">Conjunto de Anúncios</h2>
                <p className="text-sm text-ch-text-muted">Defina quem verá seus anúncios e quanto você quer gastar.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* Nome do AdSet */}
                <div className="col-span-1 md:col-span-2 space-y-2">
                    <Label htmlFor="adset-name">Nome do Conjunto</Label>
                    <Input
                        id="adset-name"
                        value={data.name}
                        onChange={(e) => updateData({ name: e.target.value })}
                        className="bg-ch-dark-gray border-ch-dark-gray text-ch-white"
                    />
                </div>

                {/* Orçamento Diário */}
                <div className="space-y-2">
                    <Label htmlFor="budget">Orçamento Diário (R$)</Label>
                    <div className="relative">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-ch-text-muted">R$</span>
                        <Input
                            id="budget"
                            type="number"
                            step="0.01"
                            min="1.00"
                            defaultValue={currentBudget}
                            onBlur={(e) => handleBudgetChange(e.target.value)}
                            className="pl-10 bg-ch-dark-gray border-ch-dark-gray text-ch-white"
                        />
                    </div>
                    <p className="text-xs text-ch-text-dimmed">Valor mínimo recomendado: R$ 6,00</p>
                </div>

                {/* Otimização */}
                <div className="space-y-2">
                    <Label htmlFor="optimization">Meta de Otimização</Label>
                    <Select value={data.optimization_goal} onValueChange={(v) => updateData({ optimization_goal: v as any })}>
                        <SelectTrigger id="optimization" className="bg-ch-dark-gray border-ch-dark-gray text-ch-white">
                            <SelectValue placeholder="Selecione..." />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="REACH">Alcance</SelectItem>
                            <SelectItem value="IMPRESSIONS">Impressões</SelectItem>
                            <SelectItem value="LINK_CLICKS">Cliques no Link</SelectItem>
                            <SelectItem value="OFFSITE_CONVERSIONS">Conversões</SelectItem>
                            <SelectItem value="LANDING_PAGE_VIEWS">Visualização da Página</SelectItem>
                        </SelectContent>
                    </Select>
                </div>

                {/* Evento de Cobrança */}
                <div className="space-y-2">
                    <Label htmlFor="billing">Evento de Cobrança</Label>
                    <Select value={data.billing_event} onValueChange={(v) => updateData({ billing_event: v as any })}>
                        <SelectTrigger id="billing" className="bg-ch-dark-gray border-ch-dark-gray text-ch-white">
                            <SelectValue placeholder="Quando você é cobrado?" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="IMPRESSIONS">Impressões (CPM)</SelectItem>
                            <SelectItem value="LINK_CLICKS">Cliques (CPC) - Se disponível</SelectItem>
                        </SelectContent>
                    </Select>
                </div>

                {/* Data de Início */}
                <div className="space-y-2">
                    <Label htmlFor="start-date">Início da Veiculação</Label>
                    <Input
                        id="start-date"
                        type="datetime-local"
                        // Simple approach for string date input
                        value={data.start_time ? data.start_time.slice(0, 16) : ''}
                        onChange={(e) => updateData({ start_time: new Date(e.target.value).toISOString() })}
                        className="bg-ch-dark-gray border-ch-dark-gray text-ch-white w-full block"
                    />
                </div>

                {/* Targeting Simplificado */}
                <div className="col-span-1 md:col-span-2 space-y-4 p-4 border border-ch-dark-gray rounded-lg bg-ch-bg/50">
                    <h3 className="text-md font-medium text-ch-white">Público Alvo (Targeting)</h3>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <Label>Idade Mínima</Label>
                            <Input
                                type="number"
                                min="13" max="65"
                                value={data.targeting.age_min}
                                onChange={(e) => updateData({
                                    targeting: { ...data.targeting, age_min: parseInt(e.target.value) }
                                })}
                                className="bg-ch-dark-gray border-ch-dark-gray"
                            />
                        </div>
                        <div>
                            <Label>Idade Máxima</Label>
                            <Input
                                type="number"
                                min="13" max="65"
                                value={data.targeting.age_max}
                                onChange={(e) => updateData({
                                    targeting: { ...data.targeting, age_max: parseInt(e.target.value) }
                                })}
                                className="bg-ch-dark-gray border-ch-dark-gray"
                            />
                        </div>
                    </div>

                    {/* País fixo BR por enquanto */}
                    <div>
                        <Label>Localização</Label>
                        <div className="p-2 bg-ch-dark-gray rounded text-sm text-ch-text-muted mt-1">
                            Brasil (País) - {data.targeting.geo_locations.countries.join(', ')}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase, supabaseUrl } from "@/integrations/supabase/client";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { AdStepData, CampaignWizardState } from "@/types/campaign-wizard";
import { Loader2, AlertCircle } from "lucide-react";

interface StepAnuncioProps {
    data: AdStepData;
    fullData: CampaignWizardState;
    updateData: (data: Partial<AdStepData>) => void;
}

export default function StepAnuncio({ data, fullData, updateData }: StepAnuncioProps) {
    const integrationId = fullData.integration_id;

    // Fetch Pages for the selected Integration
    const { data: pages, isLoading, error } = useQuery({
        queryKey: ['meta-pages', integrationId],
        queryFn: async () => {
            const { data: sessionData } = await supabase.auth.getSession();
            const token = sessionData.session?.access_token;

            const response = await fetch(`${supabaseUrl}/functions/v1/meta-list-pages`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({ integration_id: integrationId }),
            });

            if (!response.ok) {
                const err = await response.json();
                throw new Error(err.error || 'Failed to list pages');
            }
            const res = await response.json();
            return res.pages;
        },
        enabled: !!integrationId
    });

    const handleCreativeUpdate = (field: string, value: any) => {
        updateData({
            creative: { ...data.creative, [field]: value }
        });
    };

    return (
        <div className="space-y-6 animate-in slide-in-from-right-4">
            <div className="space-y-2">
                <h2 className="text-xl font-semibold text-ch-white">Criativo do Anúncio</h2>
                <p className="text-sm text-ch-text-muted">Configure a identidade visual e o texto do seu anúncio.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Lado Esquerdo: Identidade e Mídia */}
                <div className="space-y-6">
                    {/* Nome do Anúncio */}
                    <div className="space-y-2">
                        <Label>Nome do Anúncio</Label>
                        <Input
                            value={data.name}
                            onChange={(e) => updateData({ name: e.target.value })}
                            className="bg-ch-dark-gray border-ch-dark-gray text-ch-white"
                        />
                    </div>

                    {/* Página do Facebook / Instagram */}
                    <div className="space-y-2">
                        <Label>Página do Facebook</Label>
                        {isLoading ? (
                            <div className="flex items-center text-sm text-ch-text-muted">
                                <Loader2 className="w-4 h-4 animate-spin mr-2" /> Carregando páginas...
                            </div>
                        ) : error ? (
                            <div className="flex items-center text-sm text-red-400">
                                <AlertCircle className="w-4 h-4 mr-2" /> Erro ao carregar páginas
                            </div>
                        ) : (
                            <Select
                                value={data.creative.page_id}
                                onValueChange={(v) => handleCreativeUpdate('page_id', v)}
                            >
                                <SelectTrigger className="bg-ch-dark-gray border-ch-dark-gray text-ch-white">
                                    <SelectValue placeholder="Selecione a página" />
                                </SelectTrigger>
                                <SelectContent>
                                    {pages && pages.map((page: any) => (
                                        <SelectItem key={page.id} value={page.id}>
                                            <div className="flex items-center gap-2">
                                                {/* <img src={page.picture?.data?.url} className="w-5 h-5 rounded-full" /> */}
                                                <span>{page.name}</span>
                                            </div>
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        )}
                        <p className="text-xs text-ch-text-dimmed">Esta página representará seu anúncio.</p>
                    </div>

                    {/* Imagem (URL por enquanto) */}
                    <div className="space-y-2">
                        <Label>URL da Imagem</Label>
                        <Input
                            value={data.creative.image_url}
                            onChange={(e) => handleCreativeUpdate('image_url', e.target.value)}
                            className="bg-ch-dark-gray border-ch-dark-gray text-ch-white"
                            placeholder="https://exemplo.com/imagem.png"
                        />
                        <p className="text-xs text-ch-text-dimmed">Cole o link direto da imagem do seu criativo.</p>
                    </div>

                    {/* URL de Destino */}
                    <div className="space-y-2">
                        <Label>URL de Destino (Site)</Label>
                        <Input
                            value={data.creative.link_url}
                            onChange={(e) => handleCreativeUpdate('link_url', e.target.value)}
                            className="bg-ch-dark-gray border-ch-dark-gray text-ch-white"
                            placeholder="https://seunegocio.com.br"
                        />
                    </div>
                </div>

                {/* Lado Direito: Texto e CTA */}
                <div className="space-y-6">
                    {/* Texto Principal (Body) */}
                    <div className="space-y-2">
                        <Label>Texto Principal</Label>
                        <Textarea
                            value={data.creative.body}
                            onChange={(e) => handleCreativeUpdate('body', e.target.value)}
                            className="bg-ch-dark-gray border-ch-dark-gray text-ch-white h-32"
                            placeholder="Digite o texto que aparece acima da imagem..."
                        />
                    </div>

                    {/* Título (Headline) */}
                    <div className="space-y-2">
                        <Label>Título (Headline)</Label>
                        <Input
                            value={data.creative.title}
                            onChange={(e) => handleCreativeUpdate('title', e.target.value)}
                            className="bg-ch-dark-gray border-ch-dark-gray text-ch-white"
                            placeholder="Título abaixo da imagem"
                        />
                    </div>

                    {/* CTA */}
                    <div className="space-y-2">
                        <Label>Botão de Ação (CTA)</Label>
                        <Select
                            value={data.creative.call_to_action}
                            onValueChange={(v) => handleCreativeUpdate('call_to_action', v)}
                        >
                            <SelectTrigger className="bg-ch-dark-gray border-ch-dark-gray text-ch-white">
                                <SelectValue placeholder="Selecione o botão" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="LEARN_MORE">Saiba Mais</SelectItem>
                                <SelectItem value="SHOP_NOW">Comprar Agora</SelectItem>
                                <SelectItem value="SIGN_UP">Cadastre-se</SelectItem>
                                <SelectItem value="GET_OFFER">Obter Oferta</SelectItem>
                                <SelectItem value="CONTACT_US">Fale Conosco</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>
                </div>
            </div>

            {/* Preview Simplificado */}
            <div className="mt-8 p-4 border border-white/10 rounded-lg bg-ch-bg/50">
                <h3 className="text-sm font-medium text-ch-text-muted mb-4 uppercase text-center tracking-wider">Pré-visualização (Estilo Feed)</h3>

                <div className="max-w-md mx-auto bg-white rounded-lg overflow-hidden shadow-lg border border-gray-200">
                    {/* Header do Post */}
                    <div className="p-3 flex items-center gap-2 border-b border-gray-100">
                        <div className="font-bold text-gray-800 text-sm">
                            {data.creative.page_id ? 'Sua Página' : 'Nome da Página'}
                        </div>
                        <span className="text-gray-400 text-xs">• Patrocinado</span>
                    </div>

                    {/* Texto Principal */}
                    <div className="px-3 py-2 text-sm text-gray-800 whitespace-pre-wrap">
                        {data.creative.body || 'Texto principal do anúncio aparecerá aqui.'}
                    </div>

                    {/* Imagem */}
                    <div className="aspect-square bg-gray-100 w-full overflow-hidden">
                        {data.creative.image_url ? (
                            <img src={data.creative.image_url} alt="Ad Preview" className="w-full h-full object-cover" />
                        ) : (
                            <div className="w-full h-full flex items-center justify-center text-gray-400 text-sm">
                                Imagem do Anúncio
                            </div>
                        )}
                    </div>

                    {/* Footer/Link */}
                    <div className="bg-gray-50 px-3 py-3 flex justify-between items-center border-t border-gray-100">
                        <div className="flex-1 min-w-0 pr-4">
                            <div className="text-xs text-gray-500 uppercase truncate">
                                {data.creative.link_url ? new URL(data.creative.link_url).hostname : 'WEBSITE.COM'}
                            </div>
                            <div className="font-bold text-gray-900 text-sm truncate">
                                {data.creative.title || 'Título do Anúncio'}
                            </div>
                        </div>
                        <button className="bg-gray-200 hover:bg-gray-300 text-gray-800 text-xs font-bold py-2 px-4 rounded transition-colors whitespace-nowrap">
                            {data.creative.call_to_action?.replace('_', ' ') || 'SAIBA MAIS'}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { CampaignStepData } from "@/types/campaign-wizard";

interface StepCampanhaProps {
    data: CampaignStepData;
    updateData: (data: Partial<CampaignStepData>) => void;
    integrationId: string;
    setIntegrationId: (id: string) => void;
    integrations: any[];
}

export default function StepCampanha({
    data,
    updateData,
    integrationId,
    setIntegrationId,
    integrations
}: StepCampanhaProps) {

    return (
        <div className="space-y-6 animate-in slide-in-from-right-4">
            <div className="space-y-2">
                <h2 className="text-xl font-semibold text-ch-white">Definições da Campanha</h2>
                <p className="text-sm text-ch-text-muted">Selecione a conta de anúncio e o objetivo principal.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* Conta de Anúncios */}
                <div className="space-y-2">
                    <Label htmlFor="integration">Conta de Anúncios</Label>
                    <Select value={integrationId} onValueChange={setIntegrationId}>
                        <SelectTrigger id="integration" className="bg-ch-dark-gray border-ch-dark-gray text-ch-white">
                            <SelectValue placeholder="Selecione uma conta" />
                        </SelectTrigger>
                        <SelectContent>
                            {integrations.length === 0 ? (
                                <SelectItem value="none" disabled>Nenhuma conta ativa encontrada</SelectItem>
                            ) : (
                                integrations.map((int) => (
                                    <SelectItem key={int.id} value={int.id}>
                                        {int.account_name} ({int.account_id})
                                    </SelectItem>
                                ))
                            )}
                        </SelectContent>
                    </Select>
                </div>

                {/* Nome da Campanha */}
                <div className="space-y-2">
                    <Label htmlFor="name">Nome da Campanha</Label>
                    <Input
                        id="name"
                        value={data.name}
                        onChange={(e) => updateData({ name: e.target.value })}
                        className="bg-ch-dark-gray border-ch-dark-gray text-ch-white"
                        placeholder="Ex: Campanha Conversão Vendas"
                    />
                </div>

                {/* Objetivo */}
                <div className="space-y-2">
                    <Label htmlFor="objective">Objetivo</Label>
                    <Select value={data.objective} onValueChange={(v) => updateData({ objective: v })}>
                        <SelectTrigger id="objective" className="bg-ch-dark-gray border-ch-dark-gray text-ch-white">
                            <SelectValue placeholder="Selecione o objetivo" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="OUTCOME_SALES">Vendas (Sales)</SelectItem>
                            <SelectItem value="OUTCOME_LEADS">Leads (Cadastros)</SelectItem>
                            <SelectItem value="OUTCOME_TRAFFIC">Tráfego (Traffic)</SelectItem>
                            <SelectItem value="OUTCOME_ENGAGEMENT">Engajamento (Engagement)</SelectItem>
                            <SelectItem value="OUTCOME_AWARENESS">Reconhecimento (Awareness)</SelectItem>
                            <SelectItem value="OUTCOME_APP_PROMOTION">App Promotion</SelectItem>
                        </SelectContent>
                    </Select>
                    <p className="text-xs text-ch-text-dimmed">Selecione o objetivo que melhor se aplica ao seu negócio.</p>
                </div>

                {/* Status Inicial */}
                <div className="space-y-2">
                    <Label htmlFor="status">Status Inicial</Label>
                    <Select value={data.status} onValueChange={(v) => updateData({ status: v as 'ACTIVE' | 'PAUSED' })}>
                        <SelectTrigger id="status" className="bg-ch-dark-gray border-ch-dark-gray text-ch-white">
                            <SelectValue placeholder="Status" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="ACTIVE">Ativa (Publicar imediatamente)</SelectItem>
                            <SelectItem value="PAUSED">Pausada (Rascunho)</SelectItem>
                        </SelectContent>
                    </Select>
                </div>
            </div>
        </div>
    );
